     5→//! Saddle command - Return context needed to saddle up on a Heat
     6→
     7→use std::fs;
     8→use std::path::PathBuf;
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
    14→use crate::jjrq_query::jjrq_resolve_default_heat;
    15→
    16→/// Arguments for saddle command
    17→#[derive(clap::Args, Debug)]
    18→pub struct jjrsd_SaddleArgs {
    19→    /// Path to the Gallops JSON file
    20→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    21→    pub file: PathBuf,
    22→
    23→    /// Target Heat identity (Firemark). If omitted, uses first racing heat.
    24→    pub firemark: Option<String>,
    25→}
    26→
    27→/// Run the saddle command - return Heat context
    28→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> i32 {
    29→    let gallops = match Gallops::jjrg_load(&args.file) {
    30→        Ok(g) => g,
    31→        Err(e) => {
    32→            eprintln!("jjx_orient: error: {}", e);
    33→            return 1;
    34→        }
    35→    };
    36→
    37→    // Collect racing heats and display summary table
    38→    {
    39→        let mut racing_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter()
    40→            .filter(|(_, heat)| heat.status == HeatStatus::Racing)
    41→            .collect();
    42→
    43→        // Sort by key for stability
    44→        racing_heats.sort_by(|a, b| a.0.cmp(b.0));
    45→
    46→        if !racing_heats.is_empty() {
    47→            let mut table = jjrp_Table::jjrp_new(vec![
    48→                jjrp_Column::new("₣Fire", jjrp_Align::Left),
    49→                jjrp_Column::new("Silks", jjrp_Align::Left),
    50→                jjrp_Column::new("Status", jjrp_Align::Left),
    51→                jjrp_Column::new("Done", jjrp_Align::Right),
    52→                jjrp_Column::new("Total", jjrp_Align::Right),
    53→            ]);
    54→
    55→            // Measure all rows to compute column widths
    56→            for (key, heat) in &racing_heats {
    57→                let defined_count = heat.paces.values().filter(|pace| {
    58→                    if let Some(tack) = pace.tacks.first() {
    59→                        tack.state != PaceState::Abandoned
    60→                    } else {
    61→                        true
    62→                    }
    63→                }).count();
    64→
    65→                let completed_count = heat.paces.values().filter(|pace| {
    66→                    if let Some(tack) = pace.tacks.first() {
    67→                        tack.state == PaceState::Complete
    68→                    } else {
    69→                        false
    70→                    }
    71→                }).count();
    72→
    73→                table.jjrp_measure(&[
    74→                    key,
    75→                    &heat.silks,
    76→                    "racing",
    77→                    &completed_count.to_string(),
    78→                    &defined_count.to_string(),
    79→                ]);
    80→            }
    81→
    82→            // Print header and separator
    83→            println!("Racing-heats:");
    84→            table.jjrp_print_header();
    85→            table.jjrp_print_separator();
    86→
    87→            // Print data rows
    88→            for (key, heat) in &racing_heats {
    89→                let defined_count = heat.paces.values().filter(|pace| {
    90→                    if let Some(tack) = pace.tacks.first() {
    91→                        tack.state != PaceState::Abandoned
    92→                    } else {
    93→                        true
    94→                    }
    95→                }).count();
    96→
    97→                let completed_count = heat.paces.values().filter(|pace| {
    98→                    if let Some(tack) = pace.tacks.first() {
    99→                        tack.state == PaceState::Complete
   100→                    } else {
   101→                        false
   102→                    }
   103→                }).count();
   104→
   105→                table.jjrp_print_row(&[
   106→                    key,
   107→                    &heat.silks,
   108→                    "racing",
   109→                    &completed_count.to_string(),
   110→                    &defined_count.to_string(),
   111→                ]);
   112→            }
   113→
   114→            println!();
   115→        }
   116→    }
   117→
   118→    // Resolve firemark: use provided value or auto-select first racing heat
   119→    let firemark_str = match args.firemark {
   120→        Some(fm) => fm,
   121→        None => {
   122→            match jjrq_resolve_default_heat(&gallops) {
   123→                Ok(fm) => fm,
   124→                Err(e) => {
   125→                    eprintln!("jjx_orient: error: {}", e);
   126→                    return 1;
   127→                }
   128→            }
   129→        }
   130→    };
   131→
   132→    let firemark = match Firemark::jjrf_parse(&firemark_str) {
   133→        Ok(fm) => fm,
   134→        Err(e) => {
   135→            eprintln!("jjx_orient: error: {}", e);
   136→            return 1;
   137→        }
   138→    };
   139→
   140→    let heat_key = firemark.jjrf_display();
   141→    let heat = match gallops.heats.get(&heat_key) {
   142→        Some(h) => h,
   143→        None => {
   144→            eprintln!("jjx_orient: error: Heat '{}' not found", heat_key);
   145→            return 1;
   146→        }
   147→    };
   148→
   149→    // Check if heat is stabled (cannot saddle stabled heat)
   150→    if heat.status == HeatStatus::Stabled {
   151→        eprintln!("jjx_orient: error: Cannot saddle stabled heat '{}'", heat_key);
   152→        return 1;
   153→    }
   154→
   155→    // Read paddock file content
   156→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   157→        Ok(content) => content,
   158→        Err(e) => {
   159→            eprintln!("jjx_orient: error reading paddock file '{}': {}", heat.paddock_file, e);
   160→            return 1;
   161→        }
   162→    };
   163→
   164→    // Get recent steeplechase entries
   165→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   166→        firemark: firemark.jjrf_as_str().to_string(),
   167→        limit: 10,
   168→    }).unwrap_or_default();
   169→
   170→    // Find first actionable pace (rough or bridled)
   171→    let mut pace_coronet: Option<String> = None;
   172→    let mut pace_silks: Option<String> = None;
   173→    let mut pace_state: Option<String> = None;
   174→    let mut spec: Option<String> = None;
   175→    let mut direction: Option<String> = None;
   176→
   177→    for coronet_key in &heat.order {
   178→        if let Some(pace) = heat.paces.get(coronet_key) {
   179→            if let Some(tack) = pace.tacks.first() {
   180→                match tack.state {
   181→                    PaceState::Rough | PaceState::Bridled => {
   182→                        pace_coronet = Some(coronet_key.clone());
   183→                        pace_silks = Some(tack.silks.clone());
   184→                        pace_state = Some(match tack.state {
   185→                            PaceState::Rough => "rough".to_string(),
   186→                            PaceState::Bridled => "bridled".to_string(),
   187→                            _ => unreachable!(),
   188→                        });
   189→                        spec = Some(tack.text.clone());
   190→                        if tack.state == PaceState::Bridled {
   191→                            direction = tack.direction.clone();
   192→                        }
   193→                        break;
   194→                    }
   195→                    _ => continue,
   196→                }
   197→            }
   198→        }
   199→    }
   200→
   201→    // Determine heat status string
   202→    let status_str = match heat.status {
   203→        HeatStatus::Racing => "racing",
   204→        HeatStatus::Stabled => "stabled",
   205→        HeatStatus::Retired => "retired",
   206→    };
   207→
   208→    // Output plain text format
   209→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   210→    println!("Paddock: {}", heat.paddock_file);
   211→    println!();
   212→    println!("Paddock-content:");
   213→    for line in paddock_content.lines() {
   214→        println!("  {}", line);
   215→    }
   216→    println!();
   217→
   218→    if let Some(coronet) = pace_coronet {
   219→        if let Some(silks) = pace_silks {
   220→            if let Some(state) = pace_state {
   221→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   222→                println!();
   223→                if let Some(spec_text) = spec {
   224→                    println!("Docket:");
   225→                    for line in spec_text.lines() {
   226→                        println!("  {}", line);
   227→                    }
   228→                    println!();
   229→                }
   230→                if let Some(dir_text) = direction {
   231→                    println!("Warrant:");
   232→                    for line in dir_text.lines() {
   233→                        println!("  {}", line);
   234→                    }
   235→                    println!();
   236→                }
   237→            }
   238→        }
   239→    }
   240→
   241→    // Output recent work table
   242→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
   243→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
   244→        if let Some(ref action) = entry.action {
   245→            action == "n" || action == "A" || action == "d"
   246→        } else {
   247→            false
   248→        }
   249→    }).collect();
   250→
   251→    if !filtered_work.is_empty() {
   252→        println!("Recent-work:");
   253→
   254→        let mut table = jjrp_Table::jjrp_new(vec![
   255→            jjrp_Column::new("Commit", jjrp_Align::Left),
   256→            jjrp_Column::new("Identity", jjrp_Align::Left),
   257→            jjrp_Column::new("Subject", jjrp_Align::Left),
   258→        ]);
   259→
   260→        // Measure all rows to compute column widths
   261→        for entry in &filtered_work {
   262→            let identity_str = if let Some(ref coronet) = entry.coronet {
   263→                coronet.clone()
   264→            } else {
   265→                heat_key.clone()
   266→            };
   267→            table.jjrp_measure(&[
   268→                &entry.commit,
   269→                &identity_str,
   270→                &entry.subject,
   271→            ]);
   272→        }
   273→
   274→        // Print header and separator
   275→        table.jjrp_print_header();
   276→        table.jjrp_print_separator();
   277→
   278→        // Print data rows
   279→        for entry in &filtered_work {
   280→            let identity_str = if let Some(ref coronet) = entry.coronet {
   281→                coronet.clone()
   282→            } else {
   283→                heat_key.clone()
   284→            };
   285→            table.jjrp_print_row(&[
   286→                &entry.commit,
   287→                &identity_str,
   288→                &entry.subject,
   289→            ]);
   290→        }
   291→    }
   292→
   293→    // Call invitatory to check/create officium marker
   294→    if let Err(e) = vvc::vvcp_invitatory().await {
   295→        eprintln!("jjx_orient: warning: invitatory failed: {}", e);
   296→    }
   297→
   298→    0
   299→}
   300→

