   496→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
   497→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
   498→    match index {
   499→        0..=8 => Some((b'1' + index as u8) as char),
   500→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
   501→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
   502→        _ => None,
   503→    }
   504→}
