   506→/// Print commit swim lanes for a heat: paces × commits matrix.
   507→///
   508→/// Shows when work happened on each pace and how work interleaved.
   509→/// Called after file-touch bitmap in heat parade.
   510→fn zjjrpd_print_commit_swimlanes(firemark: &Firemark, heat: &Heat) {
   511→    let rein_args = jjrs_ReinArgs {
   512→        firemark: firemark.jjrf_as_str().to_string(),
   513→        limit: 10000,
   514→    };
   515→
   516→    let entries = match jjrs_get_entries(&rein_args) {
   517→        Ok(e) => e,
   518→        Err(e) => {
   519→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
   520→            return;
   521→        }
   522→    };
   523→
   524→    if entries.is_empty() {
   525→        return;
   526→    }
   527→
   528→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
   529→    let total_commits = entries.len();
   530→    let max_commits: usize = 35;
   531→    let truncated = total_commits > max_commits;
   532→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
   533→        .iter()
   534→        .take(max_commits)
   535→        .collect::<Vec<_>>()
   536→        .into_iter()
   537→        .rev()
   538→        .collect();
   539→
   540→    // Build pace rows: ordered by first chronological appearance
   541→    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
   542→    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
   543→    let mut has_heat_level = false;
   544→
   545→    for entry in &display_entries {
   546→        if let Some(ref coronet) = entry.coronet {
   547→            if !pace_index.contains_key(coronet) {
   548→                let idx = pace_order.len();
   549→                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
   550→                let ch = raw.chars().last().unwrap_or('?');
   551→                let silks = heat.paces.get(coronet)
   552→                    .and_then(|p| p.tacks.first())
   553→                    .map(|t| t.silks.clone())
   554→                    .unwrap_or_else(|| "unknown".to_string());
   555→                pace_index.insert(coronet.clone(), idx);
   556→                pace_order.push((coronet.clone(), ch, silks));
   557→            }
   558→        } else {
   559→            has_heat_level = true;
   560→        }
   561→    }
   562→
   563→    let total_rows = pace_order.len() + if has_heat_level { 1 } else { 0 };
   564→    let heat_row_idx = pace_order.len();
   565→
   566→    if total_rows == 0 {
   567→        return;
   568→    }
   569→
   570→    // Build bitmap: rows × columns
   571→    let num_cols = display_entries.len();
   572→    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
   573→    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
   574→
   575→    for (col, entry) in display_entries.iter().enumerate() {
   576→        if let Some(ref coronet) = entry.coronet {
   577→            if let Some(&row) = pace_index.get(coronet) {
   578→                bitmap[row][col] = true;
   579→                row_commit_counts[row] += 1;
   580→            }
   581→        } else if has_heat_level {
   582→            bitmap[heat_row_idx][col] = true;
   583→            row_commit_counts[heat_row_idx] += 1;
   584→        }
   585→    }
   586→
   587→    // Print
   588→    println!();
   589→    println!("Commit swim lanes (x = commit affiliated with pace):");
   590→    println!();
   591→
   592→    if truncated {
   593→        println!("(showing last {} of {} commits)", max_commits, total_commits);
   594→        println!();
   595→    }
   596→
   597→    // Vertical legend
   598→    for (i, (_, ch, silks)) in pace_order.iter().enumerate() {
   599→        println!("  {} {} {}", i + 1, ch, silks);
   600→    }
   601→    if has_heat_level {
   602→        println!("  {} * heat-level", pace_order.len() + 1);
   603→    }
   604→    println!();
   605→
   606→    // Column header line
   607→    let header: String = (0..num_cols).filter_map(zjjrpd_commit_index_char).collect();
   608→    println!("{}", header);
   609→
   610→    // Bitmap rows
   611→    for row in 0..total_rows {
   612→        let bits: String = bitmap[row].iter().map(|&b| if b { 'x' } else { '·' }).collect();
   613→        let (term_char, count) = if row < pace_order.len() {
   614→            (pace_order[row].1, row_commit_counts[row])
   615→        } else {
   616→            ('*', row_commit_counts[row])
   617→        };
   618→        println!("{}  {}  {}c", bits, term_char, count);
   619→    }
   620→}
