   622→/// Print files-per-commit bitmap for a single pace.
   623→///
   624→/// Shows which files each commit in this pace touched.
   625→/// Called after tack history in pace parade.
   626→fn zjjrpd_print_pace_commits(firemark: &Firemark, coronet_key: &str) {
   627→    let rein_args = jjrs_ReinArgs {
   628→        firemark: firemark.jjrf_as_str().to_string(),
   629→        limit: 10000,
   630→    };
   631→
   632→    let entries = match jjrs_get_entries(&rein_args) {
   633→        Ok(e) => e,
   634→        Err(e) => {
   635→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
   636→            return;
   637→        }
   638→    };
   639→
   640→    // Filter by coronet, then reverse for chronological order
   641→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
   642→        .iter()
   643→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
   644→        .collect::<Vec<_>>()
   645→        .into_iter()
   646→        .rev()
   647→        .collect();
   648→
   649→    if pace_entries.is_empty() {
   650→        return;
   651→    }
   652→
   653→    // Get files for each commit
   654→    let num_commits = pace_entries.len();
   655→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
   656→
   657→    for (col, entry) in pace_entries.iter().enumerate() {
   658→        let files = zjjrq_files_for_commit(&entry.commit);
   659→        for path in files {
   660→            if zjjrq_is_infra_file(&path) {
   661→                continue;
   662→            }
   663→            let bare = zjjrq_bare_filename(&path);
   664→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
   665→            row[col] = true;
   666→        }
   667→    }
   668→
   669→    if file_touches.is_empty() {
   670→        println!();
   671→        println!("Pace commits: (no project file commits)");
   672→        return;
   673→    }
   674→
   675→    println!();
   676→    println!("Pace commits (x = commit touched file):");
   677→    println!();
   678→
   679→    // Legend: commit index char, SHA, subject
   680→    for (i, entry) in pace_entries.iter().enumerate() {
   681→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
   682→        println!("  {} {}  {}", ch, entry.commit, entry.subject);
   683→    }
   684→    println!();
   685→
   686→    // Column header line
   687→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
   688→    println!("{}", header);
   689→
   690→    // Group by identical touch pattern
   691→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
   692→    for (filename, pattern) in &file_touches {
   693→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
   694→    }
   695→    for files in pattern_groups.values_mut() {
   696→        files.sort();
   697→    }
   698→
   699→    // Sort: more touches first, then lexicographic
   700→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
   701→    sorted.sort_by(|(a, _), (b, _)| {
   702→        let ca: usize = a.iter().filter(|&&v| v).count();
   703→        let cb: usize = b.iter().filter(|&&v| v).count();
   704→        cb.cmp(&ca).then_with(|| a.cmp(b))
   705→    });
   706→
   707→    for (pattern, files) in &sorted {
   708→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
   709→        println!("{} {}", bits, files.join(", "));
   710→    }
   711→}
