    30→/// Run the revise_docket command
    31→///
    32→/// Updates the docket text for a pace from stdin.
    33→pub fn jjrtl_run_revise_docket(args: jjrtl_ReviseDocketArgs) -> i32 {
    34→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
    35→
    36→    // Acquire lock FIRST - fail fast if another operation is in progress
    37→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
    38→        Ok(l) => l,
    39→        Err(e) => {
    40→            eprintln!("jjx_revise_docket: error: {}", e);
    41→            return 1;
    42→        }
    43→    };
    44→
    45→    let text = match read_stdin_optional() {
    46→        Ok(Some(t)) => t,
    47→        Ok(None) => {
    48→            eprintln!("jjx_revise_docket: error: docket text required via stdin");
    49→            return 1;
    50→        }
    51→        Err(e) => {
    52→            eprintln!("jjx_revise_docket: error: {}", e);
    53→            return 1;
    54→        }
    55→    };
    56→
    57→    let mut gallops = match Gallops::jjrg_load(&args.file) {
    58→        Ok(g) => g,
    59→        Err(e) => {
    60→            eprintln!("jjx_revise_docket: error loading Gallops: {}", e);
    61→            return 1;
    62→        }
    63→    };
    64→
    65→    // Get firemark and silks for commit message before we move args
    66→    let coronet_str = args.coronet.clone();
    67→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
    68→        Ok(c) => {
    69→            let parent_fm = c.jjrf_parent_firemark();
    70→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
    71→                .and_then(|h| h.paces.get(&c.jjrf_display()))
    72→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
    73→                .unwrap_or_else(|| coronet_str.clone());
    74→            (parent_fm, silks)
    75→        }
    76→        Err(e) => {
    77→            eprintln!("jjx_revise_docket: error: {}", e);
    78→            return 1;
    79→        }
    80→    };
    81→
    82→    let tally_args = LibTallyArgs {
    83→        coronet: args.coronet,
    84→        state: None,
    85→        direction: None,
    86→        text: Some(text),
    87→        silks: None,
    88→    };
    89→
    90→    match gallops.jjrg_tally(tally_args) {
    91→        Ok(()) => {
    92→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
    93→
    94→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
    95→                Ok(hash) => {
    96→                    println!("committed {}", hash);
    97→                    0
    98→                }
    99→                Err(e) => {
   100→                    eprintln!("jjx_revise_docket: error: {}", e);
   101→                    1
   102→                }
   103→            }
   104→        }
   105→        Err(e) => {
   106→            eprintln!("jjx_revise_docket: error: {}", e);
   107→            1
   108→        }
   109→    }
   110→    // lock released here
   111→}
