   126→/// Sets pace state to bridled with warrant from stdin.
   127→/// Creates both a tally commit and a B commit.
   128→pub fn jjrtl_run_arm(args: jjrtl_ArmArgs) -> i32 {
   129→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
   130→
   131→    // Acquire lock FIRST - fail fast if another operation is in progress
   132→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
   133→        Ok(l) => l,
   134→        Err(e) => {
   135→            eprintln!("jjx_arm: error: {}", e);
