   137→        }
   138→    };
   139→
   140→    let warrant = match read_stdin_optional() {
   141→        Ok(Some(w)) => w,
   142→        Ok(None) => {
   143→            eprintln!("jjx_arm: error: warrant text required via stdin");
   144→            return 1;
   145→        }
   146→        Err(e) => {
   147→            eprintln!("jjx_arm: error: {}", e);
   148→            return 1;
   149→        }
   150→    };
   151→
   152→    let mut gallops = match Gallops::jjrg_load(&args.file) {
   153→        Ok(g) => g,
   154→        Err(e) => {
   155→            eprintln!("jjx_arm: error loading Gallops: {}", e);
   156→            return 1;
   157→        }
   158→    };
   159→
   160→    // Get firemark and silks for commit message before we move args
   161→    let coronet_str = args.coronet.clone();
   162→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
   163→        Ok(c) => {
   164→            let parent_fm = c.jjrf_parent_firemark();
   165→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
   166→                .and_then(|h| h.paces.get(&c.jjrf_display()))
   167→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
   168→                .unwrap_or_else(|| coronet_str.clone());
   169→            (parent_fm, silks)
   170→        }
   171→        Err(e) => {
   172→            eprintln!("jjx_arm: error: {}", e);
   173→            return 1;
   174→        }
   175→    };
   176→
   177→    let tally_args = LibTallyArgs {
   178→        coronet: args.coronet,
   179→        state: Some(PaceState::Bridled),
   180→        direction: Some(warrant.clone()),
   181→        text: None,
   182→        silks: None,
   183→    };
   184→
   185→    match gallops.jjrg_tally(tally_args) {
   186→        Ok(()) => {
   187→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
   188→
   189→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
   190→                Ok(hash) => {
   191→                    println!("committed {}", hash);
   192→                }
   193→                Err(e) => {
   194→                    eprintln!("jjx_arm: error: {}", e);
   195→                    return 1;
   196→                }
   197→            }
   198→
   199→            // Create B commit for bridling
   200→            let coronet = match Coronet::jjrf_parse(&coronet_str) {
   201→                Ok(c) => c,
   202→                Err(e) => {
   203→                    eprintln!("jjx_arm: error parsing coronet for B commit: {}", e);
   204→                    return 1;
   205→                }
   206→            };
   207→
   208→            let agent = "arm"; // Agent that bridled the pace
   209→
   210→            // Build B commit message
   211→            use crate::jjrn_notch::jjrn_format_bridle_message;
   212→            let b_subject = jjrn_format_bridle_message(&coronet, agent, &silks);
   213→            let b_message = format!("{}\n\n{}", b_subject, warrant);
   214→
   215→            // Create empty B commit using git directly (like chalk markers)
   216→            use std::process::Command;
   217→            let output = Command::new("git")
   218→                .args(["commit", "--allow-empty", "-m", &b_message])
   219→                .output();
   220→
   221→            match output {
   222→                Ok(result) if result.status.success() => {
   223→                    // Get commit hash
   224→                    let hash_output = Command::new("git")
   225→                        .args(["rev-parse", "HEAD"])
   226→                        .output();
   227→
   228→                    if let Ok(hash_result) = hash_output {
   229→                        if hash_result.status.success() {
   230→                            let hash = String::from_utf8_lossy(&hash_result.stdout).trim().to_string();
   231→                            println!("B commit {}", &hash[..8.min(hash.len())]);
   232→                        }
   233→                    }
   234→                }
   235→                Ok(result) => {
   236→                    let stderr = String::from_utf8_lossy(&result.stderr);
   237→                    eprintln!("jjx_arm: error creating B commit: {}", stderr);
   238→                    return 1;
   239→                }
   240→                Err(e) => {
   241→                    eprintln!("jjx_arm: error creating B commit: {}", e);
   242→                    return 1;
   243→                }
   244→            }
   245→
   246→            0
   247→        }
   248→        Err(e) => {
   249→            eprintln!("jjx_arm: error: {}", e);
   250→            1
   251→        }
   252→    }
   253→    // lock released here
   254→}
